(window.webpackJsonp=window.webpackJsonp||[]).push([[337],{964:function(n,e){n.exports="\x3c!--\ntitle: 02-Ajax入门\nsort: \n--\x3e \n\n## load\n\n```js\nvar text1 = $('#text1')\nvar text2 = $('#text2')\nvar text3 = $('#text3')\nvar info = $('#info')\n\n// 加载\ninfo.load(\"/api/info\")\n// 使用load发送get请求\ntext2.load('/api/getdata?name=gdy')\n// 使用load发送Post请求\ntext3.load(\"/api/getjson\",{\"data\":\"bili\"})\n```\n\n> 异步加载\n\n```js\nvar trigger = $('#trigger');\nvar card = $('#card');\nvar loaded;\n// 点击trigger触发加载\ntrigger.click(() => {\n  // 如果visable，缓出\n  if (card.is(':visible')) {\n    card.slideUp();\n  } else {\n    if (!loaded) {\n      card.load('card.html');\n      loaded = true;\n    }\n    card.slideDown();\n  }\n})\n```\n\n## ajax\n\n```js\n$.ajax('/login', {\n  method: 'POST',\n  data: {\n    username: 'fzf',\n    password: 'password'\n  },\n  success: data => {},\n  error: () => {}\n})\n\n// get or post\n$.get('url',func);\n$.getJSON('url',func);\n$.post('url',{\n    data: '...',\n    data2: '...'.\n},func);\n\n// 重定向页面\nwindow.location.href = \"/\";\n\n// 上传图片\n$('#uploadimg').on('change', (event) => {\n  // console.log(event.target.files[0].name);\n  var uploadURL = '/api/upimg'\n  var formData = new FormData();\n  formData.append('img', event.target.files[0])\n  // ajax上传图片\n  $.ajax(uploadURL, {\n    method: 'POST',\n    data: formData,\n    contentType: false,\n    processData: false,\n    beforeSend: xhr => {\n      token = window.localStorage.getItem('token');\n      xhr.setRequestHeader(\"Authorization\", \"Bearer \" + token);\n    },\n    // 得到响应的处理\n    success: data => {\n    },\n    // 未响应的处理\n    error: () => {\n    }\n  })\n})\n```\n\n## Token\n\n```js\n// 存储Token\nwindow.localStorage.setItem('token', data.data.token);\n// 获取token\nwindow.localStorage.getItem('token')\n\n// ajax请求\n$.ajax(myinfoURL, {\n  method: 'POST',\n  beforeSend: xhr => {\n    token = window.localStorage.getItem('token');\n    xhr.setRequestHeader(\"Authorization\", \"Bearer \" + token);\n  },\n  success: () => {},\n});\n```\n\n"}}]);